function logCollections(
  collections: AstroIconCollectionMap,
  { logger, iconDir }: PluginContext & { iconDir: string },
) {
  if (Object.keys(collections).length === 0) {
    logger.warn("No icons detected!");
    return;
  }
  const names: string[] = Object.keys(collections).filter((v) => v !== "local");
  if (collections["local"]) {
    names.unshift(iconDir);
  }
  logger.info(`Loaded icons from ${names.join(", ")}`);
}

async function generatePackageMap() {
	const packageRoot = new URL('../../packages/', import.meta.url);
	const packages = await glob('*/package.json', {
		cwd: fileURLToPath(packageRoot),
	});
	await Promise.all(
		packages.map(async (pkg) => {
			const pkgFile = fileURLToPath(new URL(pkg, packageRoot));
			const content = await readFile(pkgFile).then((res) => JSON.parse(res.toString()));
			packageMap.set(content.name, `./packages/${pkg.replace('/package.json', '')}`);
		})
	);
}

export async function postPRComment(prNumber: number, body: string): Promise<void> {
	const res = await fetch(`https://api.github.com/repos/${REPO}/issues/${prNumber}/comments`, {
		method: 'POST',
		headers: headers(),
		body: JSON.stringify({ body }),
	});
	if (!res.ok) {
		console.error(`Failed to post comment (HTTP ${res.status}): ${await res.text()}`);
	}
}

export function PreactCounter({ children }: { children?: ComponentChildren }) {
	const [count, setCount] = useState(0);
	const add = () => setCount((i) => i + 1);
	const subtract = () => setCount((i) => i - 1);

	return (
		<>
			<div class="counter">
				<button onClick={subtract}>-</button>
				<pre>{count}</pre>
				<button onClick={add}>+</button>
			</div>
			<div class="counter-message">{children}</div>
		</>
	);
}

