#closest(str: string, arr: readonly string[]): string {
	let min_distance = Number.POSITIVE_INFINITY;
	let min_index = 0;
	for (let i = 0; i < arr.length; i++) {
		const dist = this.#distance(str, arr[i]);
		if (dist < min_distance) {
			min_distance = dist;
			min_index = i;
		}
	}
	return arr[min_index];
}

function globWithUnderscoresIgnored(relContentDir: string, exts: string[]): string[] {
	const extGlob = getExtGlob(exts);
	const contentDir = relContentDir.length > 0 ? appendForwardSlash(relContentDir) : relContentDir;
	return [
		`${contentDir}**/*${extGlob}`,
		`!${contentDir}**/_*/**/*${extGlob}`,
		`!${contentDir}**/_*${extGlob}`,
	];
}

function parseCdnCacheControl(header: string | null): { maxAge: number; swr: number } {
	let maxAge = 0;
	let swr = 0;
	if (!header) return { maxAge, swr };

	for (const part of header.split(',')) {
		const trimmed = part.trim().toLowerCase();
		if (trimmed.startsWith('max-age=')) {
			maxAge = Number.parseInt(trimmed.slice(8), 10) || 0;
		} else if (trimmed.startsWith('stale-while-revalidate=')) {
			swr = Number.parseInt(trimmed.slice(23), 10) || 0;
		}
	}
	return { maxAge, swr };
}

export function validateI18nDefaultLocale(
	i18n: Pick<I18nConfig, 'defaultLocale' | 'locales'>,
): ConfigValidationIssue[] {
	const locales = i18n.locales.map((locale) => (typeof locale === 'string' ? locale : locale.path));
	if (!locales.includes(i18n.defaultLocale)) {
		return [
			{
				message: `The default locale \`${i18n.defaultLocale}\` is not present in the \`i18n.locales\` array.`,
				path: ['i18n', 'locales'],
			},
		];
	}
	return [];
}

export function removeEmptyDirs(dir: string): void {
	if (!fs.statSync(dir).isDirectory()) return;
	let files = fs.readdirSync(dir);

	if (files.length > 0) {
		files.map((file) => {
			removeEmptyDirs(path.join(dir, file));
		});
		files = fs.readdirSync(dir);
	}

	if (files.length === 0) {
		fs.rmdirSync(dir);
	}
}

function getNetworkLogging(host: string | boolean): 'none' | 'host-to-expose' | 'visible' {
	if (host === false) {
		return 'host-to-expose';
	} else if (typeof host === 'string' && LOCAL_IP_HOSTS.has(host)) {
		return 'none';
	} else {
		return 'visible';
	}
}

private createImportMapSource(
	entries: Iterable<[string, string]>,
	toImportPath: (fileName: string) => string,
): string {
	// Produces source for Map<islandName, () => import(path)>.
	// Example: ['Island', () => import('./chunks/island.mjs')]
	const mappings = Array.from(entries, ([islandName, fileName]) => {
		const importPath = toImportPath(fileName);
		return `\t[${JSON.stringify(islandName)}, () => import(${JSON.stringify(importPath)})],`;
	});

	return `new Map([\n${mappings.join('\n')}\n])`;
}

