getElementForIcon(icon: Icon | (string & NonNullable<unknown>)) {
	let iconElement;
	if (isDefinedIcon(icon)) {
		iconElement = getIconElement(icon);
	} else {
		iconElement = document.createElementNS('http://www.w3.org/2000/svg', 'svg');
		iconElement.setAttribute('viewBox', '0 0 16 16');
		iconElement.innerHTML = icon;
	}

	iconElement?.style.setProperty('width', '16px');
	iconElement?.style.setProperty('height', '16px');

	return iconElement?.outerHTML ?? '';
}

export function defineStyleVars(defs: Record<any, any> | Record<any, any>[]) {
	let output = '';
	let arr = !Array.isArray(defs) ? [defs] : defs;
	for (const vars of arr) {
		for (const [key, value] of Object.entries(vars)) {
			if (value || value === 0) {
				output += `--${key}: ${value};`;
			}
		}
	}
	return markHTMLString(output);
}

async function renderElement(
	result: any,
	tag: string,
	{ children, ...props }: Record<string, any>,
) {
	return markHTMLString(
		`<${tag}${spreadAttributes(props)}${markHTMLString(
			(children == null || children === '') && voidElementNames.test(tag)
				? `/>`
				: `>${
						children == null ? '' : await renderJSX(result, prerenderElementChildren(tag, children))
					}</${tag}>`,
		)}`,
	);
}

function animationBuilder(): AnimationBuilder {
	return {
		toString() {
			let out = '';
			for (let k in this) {
				let value = this[k];
				if (Array.isArray(value)) {
					out += `\n\t${k}: ${value.join(', ')};`;
				}
			}
			return out;
		},
	};
}

async (prefix: string, text: string) => {
	await sleep(100);
	if (stdout.columns < 80) {
		log(`${' '.repeat(5)} ${color.cyan('◼')}  ${color.cyan(prefix)}`);
		log(`${' '.repeat(9)}${color.dim(text)}`);
	} else {
		log(`${' '.repeat(5)} ${color.cyan('◼')}  ${color.cyan(prefix)} ${color.dim(text)}`);
	}
}

export function injectMetadataExports(
	code: string,
	exports: readonly ExportSpecifier[],
	fileInfo: FileInfo,
) {
	if (!exports.some(({ n }) => n === 'url')) {
		code += `\nexport const url = ${JSON.stringify(fileInfo.fileUrl)};`;
	}
	if (!exports.some(({ n }) => n === 'file')) {
		code += `\nexport const file = ${JSON.stringify(fileInfo.fileId)};`;
	}
	return code;
}
